import { Form, Spin } from "antd"
import { useEffect, useState } from "react"
import { useSelector } from "react-redux"
import CustomModal from "src/components/Modal/CustomModal"
import Button from "src/components/MyButton/Button"
import Notice from "src/components/Notice"
import ContactService from "src/services/Contacts"
import MemberService from "src/services/MemberService"
import PositionService from "src/services/PositionService"
import OrganForm from "../components/OrganForm"
import PersonForm from "../components/PersonForm"

const ModalAddMember = ({
  open,
  onCancel,
  onOk,
  selectedNode,
  listUnit,
  memberType,
}) => {
  const isEdit = open?.MemberID
  const [form] = Form.useForm()
  const { listSystemKey } = useSelector(state => state.appGlobal)
  const [loading, setLoading] = useState(false)
  const [listPosition, setListPos] = useState([])
  const [member, setMember] = useState([])

  const handleSubmit = () => {
    form.validateFields().then(values => {
      setLoading(true)
      ContactService[isEdit ? "updateMember" : "insertMember"]({
        ...values,
        AccountID: AccountID,
        UserID: isEdit ? isEdit?.UserID : undefined,
      })
        .then(res => {
          if (res.isOk) {
            Notice({ msg: `${isEdit ? "Cập nhật" : "Thêm mới"} thành công.` })
            onOk()
            onCancel()
          }
        })
        .finally(() => setLoading(false))
    })
  }

  const getListPos = body => {
    setLoading(true)
    PositionService.getAllPosition(body)
      .then(res => {
        if (res.isOk) setListPos(res?.Object)
      })
      .finally(() => {
        setLoading(false)
      })
  }
  const getDetailMember = async () => {
    try {
      setLoading(true)
      const res = await MemberService.GetMemberDetail({
        memberId: open?.MemberID,
        memberType: open?.MemberType,
      })
      if (res.IsError) return
      setMember(res?.Object)
      form.setFieldsValue(res?.Object)
    } catch (error) {
      console.log("Error>>DefaultAction>>getSystemKey: ", error)
    } finally {
      setLoading(false)
    }
  }
  useEffect(() => {
    getListPos()
  }, [])
  useEffect(() => {
    if (isEdit) {
      getDetailMember()
    } else
      form.setFieldsValue({
        Status: 1,
      })
  }, [isEdit, form])

  const renderFooter = () => (
    <div className="d-flex-end">
      <Button
        btnType="primary"
        className="btn-hover-shadow"
        onClick={handleSubmit}
      >
        Ghi lại
      </Button>
    </div>
  )

  return (
    <CustomModal
      title={`${isEdit ? "Cập nhật" : "Thêm"} hội viên`}
      open={open}
      width="900px"
      onCancel={onCancel}
      footer={renderFooter()}
    >
      <Spin spinning={loading}>
        <div>
          Hiệp hội: <b>{selectedNode?.title}</b>
        </div>
        <Form form={form} layout="vertical">
          {memberType === 1 ? (
            <PersonForm
              isEdit={isEdit}
              listUnit={listUnit}
              listPosition={listPosition}
            />
          ) : (
            <OrganForm
              isEdit={isEdit}
              listUnit={listUnit}
              listPosition={listPosition}
            />
          )}
        </Form>
      </Spin>
    </CustomModal>
  )
}

export default ModalAddMember
