import { Affix } from "antd"
import { useState } from "react"
import ButtonCircle from "src/components/MyButton/ButtonCircle"
import TreeCategory from "./components/TreeCategory"
import InsertAssociationModal from "./modal/InsertAssociationModal"
import ButtonCustom from "src/components/MyButton/Button"

const ListAssociation = ({ total = 0, selectedNode, setSelectedNote }) => {
  const [openInsertAssociationModal, setOpenInsertAssociationModal] =
    useState(false)

  return (
    <div>
      <div className="d-flex-sb">
        <span className="title-type-2">Hiệp hội:</span>
        <ButtonCustom
          btnType="primary"
          className="btn-hover-shadow"
          onClick={() => setOpenInsertAssociationModal(true)}
        >
          Đăng ký
        </ButtonCustom>
      </div>
      <Affix offsetTop={45}>
        <TreeCategory
          selectedNode={selectedNode}
          setSelectedNote={setSelectedNote}
        />
      </Affix>
      {!!openInsertAssociationModal && (
        <InsertAssociationModal
          open={openInsertAssociationModal}
          onCancel={() => {
            setOpenInsertAssociationModal(false)
          }}
          onOk={() => {}}
        />
      )}
    </div>
  )
}

export default ListAssociation
