import { Spin } from "antd"
import _ from "lodash"
import React, { useEffect, useState } from "react"
import { useLocation } from "react-router-dom"
import { GUIDE_EMPTY } from "src/constants/constants"
import { removeDiacritics } from "src/lib/stringsUtils"
import AssociationService from "src/services/AssociationService"
import styled from "styled-components"
import { TreeAnchorStyled } from "../../styled"
import InsertCategory from "../modal/InsertCategory"
import SearchTree from "./SearchTree"

export const sort = items => {
  return _.orderBy(items, ["Level", "SortOrder"], ["asc", "asc"])
}

const StyleTree = styled.div`
  .ant-tree-node-content-wrapper {
    width: 100% !important;
  }
`

const TreeCategory = ({ selectedNode, setSelectedNote = () => {} }) => {
  const treeRef = React.useRef()
  const { state } = useLocation()
  const [loading, setLoading] = useState(false)
  const [open, setOpen] = useState()
  const [treeData, setTreeData] = useState({ tree: [], dataList: [] })

  const nest = (items, id, link) => {
    return items
      ?.filter(item => item[link] === id)
      .map(item => ({
        ...item,
        title: item.title,
        key: item.key,
        children: nest(items, item?.key, link),
      }))
  }

  const getListCategory = async () => {
    try {
      setLoading(true)
      const res = await AssociationService.getAssociationNameList({
        AssociationID: GUIDE_EMPTY,
        AssociationName: "",
        Status: 3,
      })
      if (res?.isError) return

      const dataList = sort(
        res?.Object?.map(item => ({
          ...item,
          key: item?.AssociationID,
          title: item?.AssociationName || "",
          removeDiacriticsTitle: removeDiacritics(
            item?.AssociationName.toLowerCase(),
          ),
          Status: item?.Status || 3,
          MemberNo: item?.MemberNo || 0,
          Image: item?.Image,
          AssociationName: item?.AssociationName,
        })),
      )

      const tree = nest(sort(dataList), GUIDE_EMPTY, "ParentID")
      setTreeData({ tree: tree, dataList: dataList })

      setSelectedNote(e =>
        !e ? (state?.selectedNode ? state?.selectedNode : tree[0]) : e,
      )
    } finally {
      setLoading(false)
    }
  }

  useEffect(() => {
    getListCategory()
  }, [])

  return (
    <Spin spinning={loading}>
      <StyleTree className="pr-10">
        <TreeAnchorStyled>
          <SearchTree
            treeDataDefault={treeData?.tree}
            dataList={treeData?.dataList}
            selectedNode={selectedNode}
            setSelectedNote={setSelectedNote}
          />
          {!!open && (
            <InsertCategory
              open={open}
              onCancel={() => setOpen(undefined)}
              onOk={getListCategory}
            />
          )}
        </TreeAnchorStyled>
      </StyleTree>
    </Spin>
  )
}

export default TreeCategory
