import { Col, Form, Row, Select, Upload } from "antd"
import { useSelector } from "react-redux"
import DatePickerCustom from "src/components/Date/DatePickerCustom"
import InputCustom from "src/components/Input/InputCustom"
import ButtonCustom from "src/components/MyButton/Button"
import SelectCustom from "src/components/Select/SelectCustom"
import { SYSTEM_KEY } from "src/constants/constants"
import { getRegexEmail, getRegexMobile } from "src/lib/stringsUtils"
import { getListComboByKey, normFile } from "src/lib/utils"

const PersonForm = ({ isEdit = false, listUnit = [], listPosition = [] }) => {
  const { listSystemKey } = useSelector(state => state.appGlobal)
  return (
    <Row gutter={16}>
      <Col span={8}>
        <Row gutter={[8, 8]}>
          <Col span={24}>
            <Form.Item
              label="Ảnh thẻ"
              name="Avatar"
              valuePropName="fileList"
              getValueFromEvent={normFile}
              rules={[
                () => ({
                  validator(_, value) {
                    if (value?.find(i => i?.size > 5 * 1024 * 1024)) {
                      return Promise.reject(
                        new Error("Dung lượng file tối đa 5MB"),
                      )
                    }
                    return Promise.resolve()
                  },
                }),
              ]}
            >
              <Upload
                accept="image/*"
                multiple={false}
                maxCount={1}
                beforeUpload={() => false}
                listType="picture-card"
              >
                <div
                  className="align-items-center p-8 ml-32"
                  style={{ background: "#fff" }}
                >
                  <ButtonCustom variant="dashed" iconName={"add-media-video"}>
                    <div className="account-text-upload ml-16">Chọn ảnh</div>
                  </ButtonCustom>
                  <div className="sub-color fs-12 ">
                    Dung lượng file tối đa 5MB, định dạng: .JPG, .JPEG, .PNG,
                    .SVG
                  </div>
                </div>
              </Upload>
            </Form.Item>
          </Col>
          <Col span={24}>
            <Form.Item
              label="Email"
              name="Email"
              rules={[
                {
                  required: true,
                  message: "Thông tin không được để trống",
                },
                {
                  pattern: getRegexEmail(),
                  message: "Email sai định dạng",
                },
              ]}
            >
              <InputCustom placeholder="Nhập email" />
            </Form.Item>
          </Col>
          <Col span={24}>
            <Form.Item
              label="Số điện thoại"
              name="PhoneNumber"
              rules={[
                {
                  pattern: getRegexMobile(),
                  message: "Số điện thoại là chuỗi từ 8 đến 15 kí tự chữ số",
                },
              ]}
            >
              <InputCustom placeholder="Nhập số điện thoại" />
            </Form.Item>
          </Col>
          <Col span={24}>
            <Form.Item label="Trạng thái" name="Status">
              <Select placeholder="chọn trạng thái">
                {getListComboByKey(SYSTEM_KEY?.STATUS, listSystemKey)?.map(
                  i => (
                    <Select.Option key={+i.CodeValue} value={+i.CodeValue}>
                      {i?.Description}
                    </Select.Option>
                  ),
                )}
              </Select>
            </Form.Item>
          </Col>
        </Row>
      </Col>
      <Col span={16}>
        <Row gutter={[8, 8]}>
          {!isEdit && (
            <Col span={12}>
              <Form.Item
                label="Tên đăng nhập"
                name="UserName"
                required
                rules={[
                  {
                    required: true,
                    message: "Thông tin không được để trống",
                  },
                ]}
              >
                <InputCustom placeholder="Nhập tên đăng nhập" />
              </Form.Item>
            </Col>
          )}
          <Col span={12}>
            <Form.Item
              label="Tên hội viên"
              name="FullName"
              rules={[
                {
                  required: true,
                  message: "Thông tin không được để trống",
                },
              ]}
            >
              <InputCustom placeholder="Nhập họ tên" />
            </Form.Item>
          </Col>
          <Col span={12}>
            <Form.Item label="Chức vụ" name="PositionID">
              <SelectCustom placeholder="Chọn">
                {listPosition?.map(i => (
                  <Select.Option key={i?.PositionID} value={i?.PositionID}>
                    {i?.PositionName}
                  </Select.Option>
                ))}
              </SelectCustom>
            </Form.Item>
          </Col>
          <Col span={12}>
            <Form.Item
              label="Số CCCD"
              name="Identity"
              rules={[
                {
                  required: true,
                  message: "Thông tin không được để trống",
                },
              ]}
            >
              <InputCustom placeholder="Nhập" />
            </Form.Item>
          </Col>
          <Col span={12}>
            <Form.Item
              label="Địa chỉ thường trú"
              name="cccd"
              rules={[
                {
                  required: true,
                  message: "Thông tin không được để trống",
                },
              ]}
            >
              <InputCustom placeholder="Nhập" />
            </Form.Item>
          </Col>
          <Col span={12}>
            <Form.Item
              label="Địa chỉ liên hệ"
              name="cccd"
              rules={[
                {
                  required: true,
                  message: "Thông tin không được để trống",
                },
              ]}
            >
              <InputCustom placeholder="Nhập" />
            </Form.Item>
          </Col>
          <Col span={12}>
            <Form.Item
              label="Ngày sinh"
              name="cccd"
              rules={[
                {
                  required: true,
                  message: "Thông tin không được để trống",
                },
              ]}
            >
              <DatePickerCustom placeholder="Nhập" />
            </Form.Item>
          </Col>
          <Col span={12}>
            <Form.Item
              label="Ngày tham gia"
              name="cccd"
              rules={[
                {
                  required: true,
                  message: "Thông tin không được để trống",
                },
              ]}
            >
              <DatePickerCustom placeholder="Nhập" />
            </Form.Item>
          </Col>
          <Col span={12}>
            <Form.Item
              label="Đơn vị"
              name="AccountID"
              required
              rules={[
                {
                  required: true,
                  message: "Thông tin không được để trống",
                },
              ]}
            >
              <Select placeholder="chọn đơn vị">
                {listUnit?.map(i => (
                  <Select.Option key={i?.AccountID} value={i?.AccountID}>
                    {i?.AccountName}
                  </Select.Option>
                ))}
              </Select>
            </Form.Item>
          </Col>
          <Col span={12}>
            <Form.Item
              label="Gói hội viên"
              name="cccd"
              rules={[
                {
                  required: true,
                  message: "Thông tin không được để trống",
                },
              ]}
            >
              <InputCustom placeholder="Nhập" />
            </Form.Item>
          </Col>
        </Row>
      </Col>
    </Row>
  )
}

export default PersonForm
