import { Avatar, Col, Divider, Form, Modal, Row, Select, Spin } from "antd"
import { useEffect, useState } from "react"
import InputCustom from "src/components/Input/InputCustom"
import Button from "src/components/MyButton/Button"
import Notice from "src/components/Notice"
import { getListComboByKey } from "src/lib/utils"
import { useSelector } from "react-redux"
import SelectCustom from "src/components/Select/SelectCustom"
import { GUIDE_EMPTY, GUIDE_ONE, SYSTEM_KEY } from "src/constants/constants"
import TreeSelectCustom from "src/components/Select/TreeSelectCustom"
import DatePickerCustom from "src/components/Date/DatePickerCustom"
import ButtonCustom from "src/components/MyButton/Button"
import {
  getRegexEmail,
  getRegexMobile,
  removeDiacritics,
} from "src/lib/stringsUtils"
import dayjs from "dayjs"
import AssociationService from "src/services/AssociationService"
import { sort } from "./TreeCategoryModal"

function InsertAssociationModal({ open, onCancel, onOk }) {
  const [form] = Form.useForm()
  const [loading, setLoading] = useState(false)
  const [treeData, setTreeData] = useState(null)
  const { listSystemKey } = useSelector(state => state.appGlobal)

  const nest = (items, id, link) => {
    return items
      ?.filter(item => item[link] === id)
      .map(item => ({
        ...item,
        title: item.title,
        key: item.key,
        value: item.key,
        children: nest(items, item?.key, link),
      }))
  }
  const getListAssoc = async () => {
    try {
      setLoading(true)
      const res = await AssociationService.getAssociationNameList({
        AssociationID: GUIDE_EMPTY,
        AssociationName: "",
        Status: 3,
      })
      if (res?.isError) {
        return
      }

      const dataList = sort(
        res?.Object?.map(item => ({
          ...item,
          key: item?.AssociationID,
          title: item?.AssociationName || "",
        })),
      )

      const tree = nest(sort(dataList), GUIDE_EMPTY, "ParentID")
      setTreeData({ tree })
    } catch (error) {
      console.log(" Lỗi khi lấy danh sách hội trực thuộc:", error)
    } finally {
      setLoading(false)
    }
  }

  const handleCreateAssoc = async () => {
    try {
      setLoading(true)
      const values = await form.validateFields()

      const res = await AssociationService.createAssociation({
        ...values,
        EstablishmentDate: values?.EstablishmentDate.format(),
        Status: 3,
      })

      if (res?.isError) return

      Notice({
        msg: "Thêm hiệp hội thành công!",
      })

      form.resetFields()
      onOk()
      onCancel()
    } catch (error) {
      console.log("error", error)
    } finally {
      setLoading(false)
    }
  }

  const handleCancel = () => {
    form.resetFields()
    onCancel()
  }

  useEffect(() => {
    if (open) {
      getListAssoc()
    } else {
      console.log("❌ Modal đóng")
    }
  }, [open])

  return (
    <Modal
      title="Đăng ký hiệp hội"
      open={open}
      onCancel={handleCancel}
      footer={null}
      width={900}
      centered
    >
      <Spin spinning={loading}>
        <Form
          form={form}
          layout="vertical"
          initialValues={{
            SortOrder: 0,
            Status: 1,
            AssociationType: 1,
            ParentId: GUIDE_ONE,
            EstablishmentDate: dayjs(),
          }}
        >
          <Row gutter={[16, 16]}>
            <Col span={8}>
              <div className="text-center">
                <Avatar
                  size={120}
                  src={undefined}
                  style={{
                    backgroundColor: "#7265e6",
                    verticalAlign: "middle",
                    boxShadow: "1px 4px 10px rgba(0,0,0,0.3)",
                    fontSize: "3rem",
                  }}
                  className="mb-8"
                >
                  H
                </Avatar>
                <div>Mã hội: (Tự tạo)</div>
                <div>Số hội viên: 0</div>
              </div>
            </Col>
            <Col span={16}>
              <Row gutter={16}>
                <Col span={24}>
                  <Form.Item
                    label="Tên hội"
                    name="Name"
                    rules={[
                      {
                        required: true,
                        message: "Thông tin không được để trống",
                      },
                    ]}
                  >
                    <InputCustom placeholder="Nhập tên hội" />
                  </Form.Item>
                </Col>
                <Col span={24}>
                  <Form.Item
                    label="Hội trực thuộc"
                    name="ParentId"
                    rules={[
                      {
                        required: true,
                        message: "Thông tin không được để trống",
                      },
                    ]}
                  >
                    <TreeSelectCustom
                      style={{ width: "100%" }}
                      styles={{
                        popup: { root: { maxHeight: 400, overflow: "auto" } },
                      }}
                      placeholder="Chọn hội trực thuộc"
                      allowClear
                      treeDefaultExpandAll
                      treeData={treeData?.tree}
                      // onDropdownVisibleChange={visible => {
                      //   console.log("🔽 TreeSelect dropdown visible:", visible)
                      //   console.log("🌳 Current treeData:", treeData)
                      //   console.log(
                      //     "📊 Tree items count:",
                      //     treeData?.tree?.length || 0,
                      //   )
                      // }}
                    />
                  </Form.Item>
                </Col>
                <Col span={24}>
                  <Form.Item
                    label="Email"
                    name="Email"
                    rules={[
                      {
                        required: true,
                        pattern: getRegexEmail(),
                        message: "Email không hợp lệ",
                      },
                    ]}
                  >
                    <InputCustom placeholder="Nhập email" />
                  </Form.Item>
                </Col>
                {/* <Col span={8}>
                  <Form.Item
                    label="Trạng thái"
                    name="Status"
                    rules={[
                      {
                        required: true,
                        message: "Thông tin không được để trống",
                      },
                    ]}
                  >
                    <SelectCustom placeholder="Chọn trạng thái">
                      {getListComboByKey(
                        SYSTEM_KEY?.ASSOCIATION_STATUS,
                        listSystemKey,
                      )?.map(i => (
                        <Select.Option key={+i.CodeValue} value={+i.CodeValue}>
                          {i?.Description}
                        </Select.Option>
                      ))}
                    </SelectCustom>
                  </Form.Item>
                </Col> */}
              </Row>
            </Col>
          </Row>

          <Divider />

          <Row gutter={16}>
            <Col span={6}>
              <Form.Item
                label="Số điện thoại"
                name="PhoneNumber"
                rules={[
                  {
                    required: true,
                    pattern: getRegexMobile(),
                    message: "Số điện thoại là chuỗi từ 10 đến 11 kí tự chữ số",
                  },
                ]}
              >
                <InputCustom placeholder="Nhập số điện thoại" />
              </Form.Item>
            </Col>
            <Col span={6}>
              <Form.Item
                label="Ngày thành lập"
                name="EstablishmentDate"
                rules={[
                  {
                    required: true,
                    message: "Thông tin không được để trống",
                  },
                ]}
              >
                <DatePickerCustom
                  disabledDate={current => current && current > dayjs()}
                  placeholder="Chọn ngày"
                  format="DD/MM/YYYY"
                />
              </Form.Item>
            </Col>
            <Col span={6}>
              <Form.Item
                label="Sắp xếp"
                name="SortOrder"
                rules={[
                  {
                    required: true,
                    message: "Thông tin không được để trống",
                  },
                ]}
              >
                <InputCustom type="number" placeholder="Nhập thứ tự" />
              </Form.Item>
            </Col>
            <Col span={6}>
              <Form.Item
                label="Loại hội"
                name="AssociationType"
                rules={[
                  {
                    required: true,
                    message: "Thông tin không được để trống",
                  },
                ]}
              >
                <SelectCustom placeholder="Chọn loại hội">
                  {getListComboByKey(
                    SYSTEM_KEY?.ASSOCIATION_TYPE,
                    listSystemKey,
                  )?.map(i => (
                    <Select.Option key={+i.CodeValue} value={+i.CodeValue}>
                      {i?.Description}
                    </Select.Option>
                  ))}
                </SelectCustom>
              </Form.Item>
            </Col>
            <Col span={24}>
              <Form.Item
                label="Địa chỉ"
                name="Address"
                rules={[
                  {
                    required: true,
                    message: "Thông tin không được để trống",
                  },
                ]}
              >
                <InputCustom placeholder="Nhập địa chỉ" />
              </Form.Item>
            </Col>
          </Row>

          <Row>
            <Col span={24} className="d-flex-end">
              <ButtonCustom className="mr-8" onClick={handleCancel}>
                Hủy
              </ButtonCustom>
              <ButtonCustom
                btnType="primary"
                onClick={handleCreateAssoc}
                loading={loading}
              >
                Thêm mới
              </ButtonCustom>
            </Col>
          </Row>
        </Form>
      </Spin>
    </Modal>
  )
}

export default InsertAssociationModal
