import { Col, Form, Input, Row, Select } from "antd"
import { useEffect, useState } from "react"
import DatePickerCustom from "src/components/Date/DatePickerCustom"
import InputCustom from "src/components/Input/InputCustom"
import CustomModal from "src/components/Modal/CustomModal"
import ButtonCustom from "src/components/MyButton/Button"
import Notice from "src/components/Notice"
import SelectCustom from "src/components/Select/SelectCustom"
import CategoryPostApi from "src/services/CategoryPost"

const InsertCategory = ({ open, onCancel, onOk, reload }) => {
  const [form] = Form.useForm()
  const [loading, setLoading] = useState(false)
  const isEdit = open?.isEdit
  useEffect(() => {
    if (isEdit)
      form.setFieldsValue({
        CategoryPostName: open?.CategoryPostName,
        Status: !!(open?.Status === 1),
        IsShowHome: !!(open?.IsShowHome === 1),
        NumericalOrder: open?.NumericalOrder,
      })
    else
      form.setFieldsValue({
        Status: true,
      })
  }, [open])

  const onSubmit = async () => {
    try {
      setLoading(true)
      const values = await form.validateFields()
      let res
      if (isEdit) {
        res = await CategoryPostApi.updateCategory({
          ...values,
          CategoryPostID: open?.key,
          type: 6,
          Status: values?.Status ? 1 : 2,
          IsShowHome: values?.IsShowHome ? 1 : 0,
        })
      } else {
        res = await CategoryPostApi.insertCategory({
          ...values,
          ParentID: open?.key,
          type: 6,
          Status: values?.Status ? 1 : 2,
          IsShowHome: values?.IsShowHome ? 1 : 0,
        })
      }
      if (res?.isError) return
      Notice({ msg: `${isEdit ? "Cập nhật" : "Thêm"} hiệp hội thành công !` })
      onOk && onOk()
      onCancel()
      reload()
    } finally {
      setLoading(false)
    }
  }
  const renderFooter = () => (
    <div className="d-flex justify-content-flex-end">
      <ButtonCustom btnType="primary" onClick={onSubmit} loading={loading}>
        {isEdit ? "Cập nhật" : "Thêm"}
      </ButtonCustom>
    </div>
  )
  return (
    <CustomModal
      title={isEdit ? "Cập nhật hiệp hội" : "Thêm hiệp hội"}
      footer={renderFooter()}
      width={1024}
      open={!!open}
      onCancel={onCancel}
    >
      {!isEdit && (
        <span>
          <b>Hiệp hội trực thuộc:</b>{" "}
          <span className="fw-600">{open?.CategoryPostName}</span>
        </span>
      )}
      <div className="mb-16" />
      <Form form={form} layout="vertical">
        <Row gutter={16}>
          <Col span={14}>
            <Form.Item
              name="CategoryPostName"
              label="Tên hiệp hội"
              required
              rules={[
                { required: true, message: "Thông tin không được để trống" },
              ]}
            >
              <Input placeholder="Nhập tên hiệp hội" />
            </Form.Item>
          </Col>
          <Col span={4}>
            <Form.Item name="NumericalOrder" label="Thứ tự">
              <InputCustom type={"number"} defaultValue={0} />
            </Form.Item>
          </Col>
          <Col span={6}>
            <Form.Item name="Status" label="Trạng thái">
              <SelectCustom
                style={{ width: "100%" }}
                maxTagCount="responsive"
                label="Trạng thái"
              >
                <Select.Option value="all" key="all">
                  Tất cả
                </Select.Option>
                <Select.Option value="personal" key="personal">
                  Đang hoạt động
                </Select.Option>
                <Select.Option value="business" key="business">
                  Ngừng hoạt động
                </Select.Option>
              </SelectCustom>
            </Form.Item>
          </Col>
          <Col span={12}>
            <Form.Item
              label="Loại hiệp hội"
              name="Status"
              valuePropName="checked"
            >
              <InputCustom placeholder="nhập" />
            </Form.Item>
          </Col>
          <Col span={12}>
            <Form.Item
              label="Ngày thành lập"
              name="Status"
              valuePropName="checked"
            >
              <DatePickerCustom placeholder="nhập" />
            </Form.Item>
          </Col>
        </Row>
      </Form>
    </CustomModal>
  )
}

export default InsertCategory
