import { Modal, Row, Col, Avatar, Tag, Divider, Typography } from 'antd';
import { UserOutlined, MailOutlined, PhoneOutlined, IdcardOutlined, BankOutlined, CalendarOutlined } from '@ant-design/icons';
import moment from 'moment';
import { COLOR_STATUS } from 'src/constants/constants';

const { Title, Text } = Typography;

const MemberDetailModal = ({ open, onCancel, memberData }) => {
  if (!memberData) return null;

  const InfoItem = ({ label, value, span = 12 }) => (
    <Col span={span}>
      <div className="member-info-item">
        <div className="info-label">
          {label}:
        </div>
        <div className="info-value">{value || '-'}</div>
      </div>
    </Col>
  );

  return (
    <>
      <Modal
        title={
          <div style={{ display: 'flex', alignItems: 'center', gap: '12px' }}>
            <Avatar
              size={40}
              src={memberData.Avatar}
              icon={<UserOutlined />}
            />
            <div>
              <Title level={4} style={{ margin: 0 }}>
                Chi tiết hội viên
              </Title>
              <Text type="secondary">{memberData.FullName}</Text>
            </div>
          </div>
        }
        open={open}
        onCancel={onCancel}
        footer={null}
        width={900}
        className="member-detail-modal"
      >
        <div className="member-detail-content">
          {/* Avatar ở giữa trên cùng */}
          <div style={{ textAlign: 'center', marginBottom: '32px' }}>
            <Avatar
              size={120}
              src={memberData.Avatar}
              icon={<UserOutlined />}
            />
          </div>

          {/* Thông tin 2 cột */}
          <Row gutter={24}>
            {/* Cột trái */}
            <Col span={12}>
              <InfoItem
                label="Tên đăng nhập"
                value={memberData.UserName}
                span={24}
              />
              <InfoItem
                label="Họ và tên"
                value={memberData.FullName}
                span={24}
              />
              <InfoItem
                label="Số CCCD"
                value={memberData.Identity}
                span={24}
              />
              <InfoItem
                label="Chức vụ, chức danh"
                value={memberData.PositionName}
                span={24}
              />
            </Col>

            {/* Cột phải */}
            <Col span={12}>
              <InfoItem
                label="Ngày gia nhập"
                value={memberData.CreateDate ? moment(memberData.CreateDate).format('DD/MM/YYYY') : ''}
                span={24}
              />
              <InfoItem
                label="Đơn vị"
                value={memberData.AccountName}
                span={24}
              />
              <InfoItem
                label="Email"
                value={memberData.Email}
                span={24}
              />
              <InfoItem
                label="Số điện thoại"
                value={memberData.PhoneNumber}
                span={24}
              />
            </Col>
          </Row>
        </div>
      </Modal>

      <style jsx global>{`
        .member-detail-modal .member-info-item {
          margin-bottom: 16px;
        }
        
        .member-detail-modal .info-label {
          font-weight: 600;
          color: #666;
          margin-bottom: 6px;
          font-size: 14px;
        }
        
        .member-detail-modal .info-value {
          font-size: 15px;
          color: #333 !important;
          word-break: break-word;
          padding: 8px 12px;
          background-color: #f8f9fa;
          border-radius: 6px;
          border: 1px solid #e9ecef;
        }
        
        .member-detail-modal .info-value * {
          color: #333 !important;
        }

        .ant-col-24 {
          flex: none !important;
        }

        .ant-modal .ant-modal-content {
          box-shadow: none !important;
        }
        
        .member-detail-content {
          padding: 20px 0;
        }
      `}</style>
    </>
  );
};

export default MemberDetailModal;