import { UserOutlined, PlusOutlined } from "@ant-design/icons"
import { Col, Row, Spin, Tooltip, message, Card, Form } from "antd"
import { useEffect, useState } from "react"
import { useSelector } from "react-redux"
import InputCustom from "src/components/Input/InputCustom"
import CustomModal from "src/components/Modal/CustomModal"
import Button from "src/components/MyButton/Button"
import SpinCustom from "src/components/SpinCustom"
import TableCustom from "src/components/Table/CustomTable"
import {
  MainTableData,
  MainTableHeader,
  SubTableData,
  SubTableHeader,
} from "src/components/Table/CustomTable/styled"
import { SYSTEM_KEY } from "src/constants/constants"
import { getListComboByKey } from "src/lib/utils"
import CategoryPostApi from "src/services/Contacts"

const ModalInsertSelectMember = ({
  open,
  onCancel,
  onOk,
  associationId,
  associationPosition,
}) => {
  const { listSystemKey } = useSelector(state => state.appGlobal)
  const [loading, setLoading] = useState(false)
  const [rowSelected, setRowSelected] = useState([])
  const [listData, setListData] = useState([])
  const [filteredData, setFilteredData] = useState([])
  const [total, setTotal] = useState(0)
  const [searchValue, setSearchValue] = useState("")
  const [pagination, setPagination] = useState({
    TextSearch: "",
    PageSize: 10, // Giữ pageSize là 10
    CurrentPage: 1,
  })

  // State cho tính năng mời email mới
  const [showEmailInput, setShowEmailInput] = useState(false)
  const [newEmail, setNewEmail] = useState("")
  const [invitingEmail, setInvitingEmail] = useState(false)

  const rowSelection = {
    selectedRowKeys: rowSelected,
    onChange: selectedRowKeys => {
      setRowSelected(selectedRowKeys)
      console.log("Row selected:", selectedRowKeys)
    },
  }

  const columns = [
    {
      title: "STT",
      dataIndex: "Index",
      key: "Index",
      width: 60,
      align: "center",
      render: (val, record, idx) => (
        <div className="text-center">
          {idx + 1 + pagination.PageSize * (pagination.CurrentPage - 1)}
        </div>
      ),
    },
    {
      title: "Avatar",
      key: "Avatar",
      dataIndex: "Avatar",
      align: "center",
      width: 80,
      render: (val, record) => (
        <div className="text-center">
          {val ? (
            <img
              src={val}
              alt="Avatar"
              style={{
                width: 40,
                height: 40,
                borderRadius: "50%",
                objectFit: "cover",
              }}
            />
          ) : (
            <div
              style={{
                width: 40,
                height: 40,
                borderRadius: "50%",
                backgroundColor: "#f0f0f0",
                display: "flex",
                alignItems: "center",
                justifyContent: "center",
                margin: "0 auto",
              }}
            >
              <UserOutlined style={{ color: "#ccc" }} />
            </div>
          )}
        </div>
      ),
    },
    {
      title: (
        <>
          <MainTableHeader>Họ tên</MainTableHeader>
          <SubTableHeader>Tên đăng nhập</SubTableHeader>
        </>
      ),
      dataIndex: "FullName",
      key: "FullName",
      align: "left",
      width: 180,
      render: (val, record) => (
        <>
          <MainTableData style={{ fontWeight: "bold" }}>
            {val || "Chưa có"}
          </MainTableData>
          <SubTableData>{record?.UserName || "Chưa có"}</SubTableData>
        </>
      ),
    },
    {
      title: (
        <>
          <MainTableHeader>Email</MainTableHeader>
          <SubTableHeader>Số điện thoại</SubTableHeader>
        </>
      ),
      dataIndex: "PhoneNumber",
      key: "PhoneNumber",
      align: "left",
      width: 200,
      render: (val, record) => (
        <>
          <MainTableData>{record?.Email || "Chưa có"}</MainTableData>
          <SubTableData>{val || "Chưa có"}</SubTableData>
        </>
      ),
    },
    {
      title: "Đơn vị",
      dataIndex: "AccountName",
      key: "AccountName",
      align: "left",
      width: 200,
      render: val => <MainTableData>{val || "Chưa có"}</MainTableData>,
    },
  ]

  // Hàm kiểm tra email hợp lệ
  const isValidEmail = email => {
    const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/
    return emailRegex.test(email)
  }

  // Hàm lọc dữ liệu phía client
  const filterDataByEmail = (data, searchText) => {
    if (!searchText) return data

    return data.filter(item => {
      const email = item?.Email?.toLowerCase() || ""
      const fullName = item?.FullName?.toLowerCase() || ""
      const userName = item?.UserName?.toLowerCase() || ""
      const searchLower = searchText.toLowerCase()

      return (
        email.includes(searchLower) ||
        fullName.includes(searchLower) ||
        userName.includes(searchLower)
      )
    })
  }

  const getList = async body => {
    try {
      setLoading(true)
      console.log("Calling API with params:", body)

      const apiParams = {
        PageSize: pagination.PageSize,
        CurrentPage: pagination.CurrentPage,
        TextSearch: body.TextSearch,
      }
      const res = await CategoryPostApi.getMembersForCategory({
        params: apiParams,
      })

      console.log("Full Response:", res)

      if (res?.StatusCode !== 200) {
        message.error(
          "Không thể tải danh sách hội viên: " +
          (res?.Message || "Lỗi không xác định"),
        )
        return
      }

      let members = []
      if (Array.isArray(res.Object)) {
        members = res.Object
      } else if (res.Object?.ListMembers) {
        members = res.Object.ListMembers
      } else if (res.Data) {
        members = Array.isArray(res.Data)
          ? res.Data
          : res.Data.ListMembers || []
      }

      // Lọc dữ liệu phía client
      const filtered = filterDataByEmail(members, body.TextSearch)

      // Kiểm tra nếu có tìm kiếm và không tìm thấy kết quả nào
      // và từ khóa tìm kiếm là một email hợp lệ
      if (
        body.TextSearch &&
        filtered.length === 0 &&
        isValidEmail(body.TextSearch)
      ) {
        setShowEmailInput(true)
        setNewEmail(body.TextSearch)
      } else {
        setShowEmailInput(false)
        setNewEmail("")
      }

      // Phân trang phía client
      const startIndex = (body.CurrentPage - 1) * body.PageSize
      const endIndex = startIndex + body.PageSize
      const paginatedData = filtered.slice(startIndex, endIndex)

      setListData(members)
      setFilteredData(paginatedData)
      setTotal(filtered.length)
    } catch (error) {
      console.error("Lỗi khi gọi API getMembersForCategory:", error)
      message.error(
        "Có lỗi xảy ra khi tải danh sách hội viên. Vui lòng thử lại.",
      )
    } finally {
      setLoading(false)
    }
  }

  // Hàm mời email mới - UPDATED với AssociationID
  const handleInviteNewEmail = async () => {
    if (!newEmail || !isValidEmail(newEmail)) {
      message.error("Vui lòng nhập email hợp lệ!")
      return
    }

    try {
      setInvitingEmail(true)

      const payload = {
        Email: newEmail,
      }

      console.log("Gửi lời mời tới email:", payload)

      const res = await CategoryPostApi.insertInvitedEmail(payload)

      console.log("Response từ API insertInvitedEmail:", res)

      if (res?.Status && !res?.isError) {
        message.success(`Đã gửi lời mời thành công tới ${newEmail}`)

        // Reset form và tìm kiếm lại
        setNewEmail("")
        setShowEmailInput(false)
        setSearchValue("")

        const newPagination = {
          ...pagination,
          TextSearch: "",
          CurrentPage: 1,
        }
        setPagination(newPagination)
        getList(newPagination)
      } else {
        message.error(
          "Gửi lời mời thất bại: " +
          (res?.Object || res?.Message || "Lỗi không xác định"),
        )
      }
    } catch (error) {
      console.error("Lỗi khi gọi API insertInvitedEmail:", error)
      message.error("Có lỗi xảy ra khi gửi lời mời. Vui lòng thử lại.")
    } finally {
      setInvitingEmail(false)
    }
  }

  const handleSearch = value => {
    console.log("Search value:", value)
    setSearchValue(value)
    const newPagination = {
      ...pagination,
      TextSearch: value.trim(),
      CurrentPage: 1,
    }
    setPagination(newPagination)
    getList(newPagination)
  }

  const handleClearSearch = () => {
    setSearchValue("")
    setShowEmailInput(false)
    setNewEmail("")
    const newPagination = {
      ...pagination,
      TextSearch: "",
      CurrentPage: 1,
    }
    setPagination(newPagination)
    getList(newPagination)
  }

  const handleSave = async () => {
    if (!rowSelected.length) {
      message.warning("Vui lòng chọn ít nhất một hội viên để mời!")
      return
    }
    try {
      setLoading(true)
      const payload = {
        UserIds: rowSelected,
        AssociationID: associationId,
        AssociationPosition: associationPosition,
      }
      console.log("Payload gửi đi:", payload)

      const res = await CategoryPostApi.insertUserAssociation(payload)
      console.log("Response từ API:", res)

      if (res?.isError || !res?.Status) {
        message.error(
          "Mời hội viên thất bại: " + (res?.Message || "Lỗi không xác định"),
        )
        return
      }

      message.success("Mời hội viên thành công")

      const selectedData = rowSelected.map(key => {
        const record = listData.find(item => item.MemberID === key)
        return {
          FullName: record?.FullName,
          MemberID: record?.MemberID,
          Email: record?.Email,
        }
      })

      !!onOk && onOk(selectedData)
      onCancel()
    } catch (error) {
      console.error("Lỗi khi gọi API insertUserAssociation:", error)
      message.error("Có lỗi xảy ra khi mời hội viên. Vui lòng thử lại.")
    } finally {
      setLoading(false)
    }
  }

  useEffect(() => {
    if (open) {
      setRowSelected([])
      setSearchValue("")
      setShowEmailInput(false)
      setNewEmail("")
      const initialPagination = {
        TextSearch: "",
        PageSize: 10, // Giữ pageSize là 10
        CurrentPage: 1,
      }
      setPagination(initialPagination)
      getList(initialPagination)
    }
  }, [open])

  return (
    <SpinCustom spinning={loading}>
      <CustomModal
        open={!!open}
        onCancel={onCancel}
        title="Mời hội viên"
        width={1000}
        footer={
          <div
            style={{
              display: "flex",
              justifyContent: "space-between",
              alignItems: "center",
              padding: "4px 0", // Giảm padding footer
            }}
          >
            <span style={{ color: "#666", fontSize: "12px" }}>
              {rowSelected.length > 0 &&
                `Đã chọn ${rowSelected.length} hội viên`}
              {searchValue && !showEmailInput && ` - Tìm thấy ${total} kết quả`}
              {showEmailInput && ` - Không tìm thấy email "${searchValue}"`}
            </span>
            <Button
              btnType="primary"
              onClick={handleSave}
              disabled={!rowSelected.length}
              loading={loading}
            >
              Mời ({rowSelected.length})
            </Button>
          </div>
        }
      >
        <Spin spinning={loading}>
          <Row gutter={[4, 4]}> {/* Giảm gutter xuống [4, 4] */}
            <Col span={24}>
              <InputCustom
                type="search"
                allowClear
                value={searchValue}
                label="Tìm kiếm theo email, tên hoặc tên đăng nhập"
                placeholder="Nhập từ khóa cần tìm hoặc email để mời"
                className="w-100"
                onChange={e => setSearchValue(e.target.value)}
                onSearch={handleSearch}
                onClear={handleClearSearch}
                style={{ marginBottom: 4 }} // Giảm margin bottom
              />
            </Col>

            {/* Hiển thị card mời email mới khi không tìm thấy */}
            {showEmailInput && (
              <Col span={24}>
                <Card
                  size="small"
                  style={{
                    backgroundColor: "#f6ffed",
                    borderColor: "#b7eb8f",
                    marginBottom: 4, // Giảm margin bottom
                    padding: "4px", // Giảm padding trong card
                  }}
                >
                  <div style={{ marginBottom: 4 }}>
                    <strong>
                      Không tìm thấy email "{searchValue}" trong hệ thống
                    </strong>
                  </div>
                  <Row gutter={[4, 0]} align="bottom">
                    <Col flex="auto">
                      <InputCustom
                        value={newEmail}
                        placeholder="Nhập email để gửi lời mời"
                        onChange={e => setNewEmail(e.target.value)}
                        onPressEnter={handleInviteNewEmail}
                        style={{ marginBottom: 0 }}
                      />
                    </Col>
                    <Col>
                      <Button
                        btnType="primary"
                        icon={<PlusOutlined />}
                        onClick={handleInviteNewEmail}
                        loading={invitingEmail}
                        disabled={!newEmail || !isValidEmail(newEmail)}
                        style={{ height: "32px" }}
                      >
                        Gửi lời mời
                      </Button>
                    </Col>
                  </Row>
                </Card>
              </Col>
            )}

            <Col span={24}>
              <TableCustom
                columns={columns}
                isPrimary
                dataSource={filteredData}
                rowKey="MemberID"
                rowSelection={rowSelection}
                scroll={{ y: 400 }}
                pagination={{
                  current: pagination.CurrentPage,
                  pageSize: pagination.PageSize,
                  total: total,
                  showSizeChanger: true,
                  showQuickJumper: true,
                  showTotal: (total, range) =>
                    `${range[0]}-${range[1]} của ${total} hội viên`,
                  onChange: (page, pageSize) => {
                    const newPagination = {
                      ...pagination,
                      CurrentPage: page,
                      PageSize: pageSize,
                    }
                    setPagination(newPagination)
                    getList(newPagination)
                  },
                }}
              />
            </Col>
          </Row>
        </Spin>
      </CustomModal>
    </SpinCustom>
  )
}

export default ModalInsertSelectMember