import { Col, Divider, Row, Select, Splitter, Tooltip, TreeSelect } from "antd"
import { saveAs } from "file-saver"
import moment from "moment"
import { useEffect, useState } from "react"
import { useSelector } from "react-redux"
import { FloatActionWrapper } from "src/components/FloatAction/styles"
import InputCustom from "src/components/Input/InputCustom"
import CB1 from "src/components/Modal/CB1"
import ButtonCustom from "src/components/MyButton/Button"
import ButtonCircle from "src/components/MyButton/ButtonCircle"
import Notice from "src/components/Notice"
import SelectCustom from "src/components/Select/SelectCustom"
import TableCustom from "src/components/Table/CustomTable"
import {
  MainTableData,
  MainTableHeader,
  SubTableData,
  SubTableHeader,
} from "src/components/Table/CustomTable/styled"
import {
  COLOR_STATUS,
  GUIDE_EMPTY,
  hideOnSinglePage,
  SYSTEM_KEY,
} from "src/constants/constants"
import { getListComboByKey } from "src/lib/utils"
import ContactsService from "src/services/Contacts"
import MemberService from "src/services/MemberService"
import ListAssociation from "./ListAssociation/ListAssociation"
import MemberDetailModal from "./modal/MemberDetailModal"
import ModalAddMember from "./modal/ModalAddMember"
import ModalInsertSelectMember from "./modal/ModalInsertSelectMember"
import { MemberPageStyle } from "./styled"

const MemberContacts = () => {
  const [selectedNode, setSelectedNote] = useState()
  const { listSystemKey } = useSelector(state => state.appGlobal)
  const [pagination, setPagination] = useState({
    PageSize: 20,
    CurrentPage: 1,
    Status: 1,
    MemberType: 1,
    AssociationID: GUIDE_EMPTY,
    Unit: null,
  })
  const [loading, setLoading] = useState(false)
  const [listData, setListData] = useState()
  const [openModalDelete, setOpenModalDelete] = useState(undefined)
  const [openModal, setOpenModal] = useState(false)
  const [openModalInsertSelectMember, setOpenModalInsertSelectMember] =
    useState(false)

  // State cho modal chi tiết hội viên
  const [openMemberDetailModal, setOpenMemberDetailModal] = useState(false)
  const [selectedMember, setSelectedMember] = useState(null)

  const [unitSelect, setUnitSelect] = useState()
  const [listUnit, setListUnit] = useState()

  const columns = [
    {
      title: "STT",
      key: "Index",
      width: 52,
      align: "center",
      memberType: [1, 2],
      render: (val, record, idx) => (
        <div className="text-center">
          {idx + 1 + pagination.PageSize * (pagination.CurrentPage - 1)}
        </div>
      ),
    },
    {
      title: "Avatar",
      key: "Avatar",
      dataIndex: "Avatar",
      align: "center",
      memberType: [1, 2],
      width: 80,
      render: (val, record) => (
        <div className="text-center">
          {val ? (
            <img
              src={val}
              alt="Avatar"
              style={{ width: 40, height: 40, borderRadius: "50%" }}
            />
          ) : (
            "-"
          )}
        </div>
      ),
    },
    {
      title: (
        <>
          <MainTableHeader>Tên đăng nhập</MainTableHeader>
          <SubTableHeader>Họ và tên</SubTableHeader>
        </>
      ),
      dataIndex: "UserName",
      key: "UserName",
      align: "center",
      memberType: [1, 2],
      width: 150,
      ellipsis: true,
      render: (val, record) => (
        <div
          style={{ cursor: "pointer" }}
          onClick={() => handleRowClick(record)}
          title={`${val || ""}\n${record?.FullName || ""}`} // Tooltip cho cả tên đăng nhập và họ tên
        >
          <MainTableData>{val}</MainTableData>
          <SubTableData>{record?.FullName}</SubTableData>
        </div>
      ),
    },
    {
      title: "Số CCCD",
      key: "Identity",
      dataIndex: "Identity",
      memberType: [1],
      width: 100,
      ellipsis: true,
      render: val => (
        <Tooltip title={val || ""}>
          <span>{val || ""}</span>
        </Tooltip>
      ),
    },
    {
      title: "Mã số thuế",
      key: "TaxCode",
      dataIndex: "TaxCode",
      memberType: [2],
      width: 120,
      ellipsis: true,
      render: val => (
        <Tooltip title={val || ""}>
          <span>{val || ""}</span>
        </Tooltip>
      ),
    },
    {
      title: (
        <>
          <MainTableHeader>Chức vụ, chức danh</MainTableHeader>
          <SubTableHeader>Ngày gia nhập</SubTableHeader>
        </>
      ),
      dataIndex: "CreateDate",
      key: "CreateDate",
      align: "center",
      memberType: [1, 2],
      width: 150,
      render: (val, record) => (
        <div
          title={`${record?.PositionName || ""}\n${
            val ? moment(val).format("DD/MM/YYYY") : ""
          }`}
        >
          <MainTableData>{record?.PositionName}</MainTableData>
          <SubTableData>
            {val ? moment(val).format("DD/MM/YYYY") : ""}
          </SubTableData>
        </div>
      ),
    },
    {
      title: (
        <>
          <MainTableHeader>Đơn vị</MainTableHeader>
        </>
      ),
      dataIndex: "AccountName",
      key: "AccountName",
      align: "center",
      memberType: [1, 2],
      width: 150,
      ellipsis: true,
      render: val => (
        <Tooltip title={val || "-"}>
          <span>{val || "-"}</span>
        </Tooltip>
      ),
    },
    {
      title: (
        <>
          <MainTableHeader>Email</MainTableHeader>
          <SubTableHeader>Số điện thoại</SubTableHeader>
        </>
      ),
      dataIndex: "PhoneNumber",
      key: "PhoneNumber",
      align: "center",
      memberType: [1, 2],
      width: 150,
      ellipsis: true,
      render: (val, record) => (
        <div title={`${record?.Email || ""}\n${val || ""}`}>
          <MainTableData>{record?.Email}</MainTableData>
          <SubTableData>{val}</SubTableData>
        </div>
      ),
    },
    {
      title: "Gói hội viên",
      key: "ghv",
      dataIndex: "ghv",
      width: 120,
      ellipsis: true,
      render: val => (
        <Tooltip title={val || ""}>
          <span>{val || ""}</span>
        </Tooltip>
      ),
    },
    {
      title: "Trạng thái",
      dataIndex: "Status",
      key: "Status",
      align: "center",
      width: 100,
      memberType: [1, 2],
      render: (val, record) => (
        <div>
          <div
            className="fw-700 text-center"
            style={
              val === 1
                ? { color: COLOR_STATUS.active }
                : { color: COLOR_STATUS.inactive }
            }
            title={val === 1 ? "Kích hoạt" : "Vô hiệu"}
          >
            {val === 1 ? "Kích hoạt" : "Vô hiệu"}
          </div>
          <FloatActionWrapper size="small" className="float-action__wrapper">
            <ButtonCircle
              className="button-circle membership-type__btn-delete"
              title="Xoá"
              iconName="deleteRow"
              onClick={e => {
                e.stopPropagation()
                handleDeleteConfirm(record)
              }}
            />
          </FloatActionWrapper>
        </div>
      ),
    },
  ]

  const deleteRank = async id => {
    try {
      const res = await MemberService.deleteMember([id])
      if (res?.isError) return
      getList()
      Notice({
        isSuccess: true,
        msg: "Xóa thành viên thành công!",
      })
    } catch (error) {
      console.log("Có lỗi xảy ra khi xóa thành viên:", error)
      Notice({
        isSuccess: false,
        msg: "Có lỗi xảy ra khi xóa thành viên!",
      })
    }
  }

  const handleDeleteConfirm = record => {
    CB1({
      title: `Bạn có chắc chắn muốn xoá <strong>"${record.FullName}"</strong> không?`,
      icon: "warning-usb",
      okText: "Đồng ý",
      cancelText: "Hủy",
      width: 500,
      warningTitle: true,
      okButtonProps: {
        style: {
          background: "#ff4d4f",
          borderColor: "#ff4d4f",
        },
      },
      onOk: close => {
        deleteRank(record.MemberID)
        close()
      },
    })
  }

  const handleRowClick = record => {
    setSelectedMember(record)
    setOpenMemberDetailModal(true)
  }

  const onReset = async ID => {
    const res = await ContactsService.resetPassword({ ID })
    if (res?.isError) return
    Notice({ msg: "Reset mật khẩu thành công!" })
  }

  const getList = async () => {
    try {
      setLoading(true)
      console.log("Pagination params:", pagination)

      const params = {
        PageSize: pagination.PageSize,
        CurrentPage: pagination.CurrentPage,
        Status: pagination.Status,
        MemberType: pagination.MemberType,
        AssociationID: pagination.AssociationID,
        TextSearch: pagination.TextSearch || "",
      }

      if (
        pagination.Unit !== null &&
        pagination.Unit !== undefined &&
        pagination.Unit !== 0
      ) {
        params.AccountID = pagination.Unit
      }

      console.log("API params:", params)

      const res = await MemberService.getListMember(params)
      if (res?.isError) return
      setListData(res?.Object)
    } finally {
      setLoading(false)
    }
  }

  const getListUnit = async () => {
    try {
      setLoading(true)
      const res = await ContactsService.getAccount({
        PageSize: 1000,
        CurrentPage: 1,
        TextSearch: "",
      })
      if (res?.isError) return
      setListUnit(res?.Object?.lstAccountVM)
      setUnitSelect(res?.Object?.lstAccountVM[0])
    } finally {
      setLoading(false)
    }
  }

  const exportAccountMember = () => {
    ContactsService.exportAccountMember({
      AccountID: unitSelect?.AccountID,
      Status: pagination.Status,
    }).then(res => {
      saveAs(res, `thành viên đơn vị ${unitSelect.AccountName}.xlsx`)
    })
  }

  const transformToTreeData = listUnit => {
    return [
      {
        title: "Tất cả",
        value: 0,
        key: 0,
      },
      {
        title: "Đơn vị",
        value: "units",
        key: "units",
        selectable: false,
        children: listUnit?.map(i => ({
          title: i?.AccountName,
          value: i.AccountID,
          key: i.AccountID,
        })),
      },
    ]
  }

  const handleUnitChange = value => {
    console.log("Unit changed:", value)
    setPagination(pre => ({
      ...pre,
      Unit: value,
      CurrentPage: 1,
    }))
  }

  const handleChangePage = (page, pageSize) => {
    let currentPage = page
    if (pageSize !== pagination?.PageSize) {
      currentPage = 1
    }
    setPagination(prev => ({
      ...prev,
      CurrentPage: currentPage,
      PageSize: pageSize,
    }))
  }

  const getDataSourceByMemberType = () => {
    if (!listData) return []

    switch (pagination.MemberType) {
      case 1:
        return listData?.ListIndividualMembers || []
      case 2:
        return listData?.ListOrganizationMembers || []
      default:
        return [
          ...(listData?.ListIndividualMembers || []),
          ...(listData?.ListOrganizationMembers || []),
        ]
    }
  }

  useEffect(() => {
    getListUnit()
  }, [])

  useEffect(() => {
    getList()
  }, [pagination])

  useEffect(() => {
    setPagination(pre => ({
      ...pre,
      AssociationID: selectedNode?.key,
      CurrentPage: 1,
    }))
  }, [selectedNode])

  return (
    <MemberPageStyle>
      <div>
        <Row gutter={[16, 16]}>
          <Col md={7} xs={24}>
            <InputCustom
              type="search"
              allowClear
              label="Tìm kiếm theo cccd/mã số thuế"
              onSearch={e =>
                setPagination(pre => ({
                  ...pre,
                  TextSearch: e,
                  CurrentPage: 1,
                }))
              }
            />
          </Col>
          <Col md={7} xs={24}>
            <TreeSelect
              style={{ width: "100%" }}
              value={pagination.Unit}
              dropdownStyle={{ maxHeight: 400, overflow: "auto" }}
              placeholder="Chọn đơn vị"
              allowClear
              treeDefaultExpandAll
              label="Đơn vị"
              onChange={handleUnitChange}
              treeData={transformToTreeData(listUnit)}
            />
          </Col>
          <Col lg={5} xs={24}>
            <SelectCustom
              label="Loại tài khoản"
              value={pagination?.MemberType}
              onChange={MemberType => {
                setPagination(pre => ({ ...pre, MemberType, CurrentPage: 1 }))
              }}
            >
              {getListComboByKey(SYSTEM_KEY?.MEMBER_TYPE, listSystemKey)?.map(
                i => (
                  <Select.Option key={+i.CodeValue} value={+i.CodeValue}>
                    {i?.Description}
                  </Select.Option>
                ),
              )}
            </SelectCustom>
          </Col>
          <Col lg={5} xs={24}>
            <SelectCustom
              label="Trạng thái"
              value={pagination?.Status}
              onChange={Status => {
                setPagination(pre => ({ ...pre, Status, CurrentPage: 1 }))
              }}
            >
              {getListComboByKey(SYSTEM_KEY?.STATUS, listSystemKey)?.map(i => (
                <Select.Option key={+i.CodeValue} value={+i.CodeValue}>
                  {i?.Description}
                </Select.Option>
              ))}
            </SelectCustom>
          </Col>
        </Row>
        <Divider className="mv-16" />
      </div>
      <Row gutter={[16, 16]}>
        <Splitter>
          <Splitter.Panel defaultSize="23%" min="15%" max="23%">
            <Col style={{ width: 400 }}>
              <ListAssociation
                selectedNode={selectedNode}
                setSelectedNote={setSelectedNote}
              />
            </Col>
          </Splitter.Panel>
          <Splitter.Panel>
            <Col flex="auto">
              <div className="title-type-1 d-flex justify-content-space-between align-items-center pb-16 pt-0 mb-16">
                <div className="fs-24">
                  Danh sách hội viên ({listData?.Totsal || 0}) :
                </div>
                <Row gutter={[16, 16]}>
                  {listData?.ButtonShow?.IsInsert && (
                    <Col>
                      <ButtonCustom
                        btnType="primary"
                        className="btn-hover-shadow"
                        onClick={() => setOpenModalInsertSelectMember(true)}
                      >
                        Mời hội viên
                      </ButtonCustom>
                    </Col>
                  )}
                </Row>
              </div>
              <TableCustom
                isPrimary
                dataSource={getDataSourceByMemberType()}
                columns={columns.filter(item =>
                  item?.memberType?.includes(pagination?.MemberType),
                )}
                sticky={{ offsetHeader: 52 }}
                scroll={{ x: 900 }}
                loading={loading}
                textEmpty="Không có thành viên nào!"
                pagination={{
                  ...pagination,
                  hideOnSinglePage: listData?.Total <= hideOnSinglePage,
                  current: pagination.CurrentPage,
                  pageSize: pagination.PageSize,
                  responsive: true,
                  total: listData?.Total,
                  locale: { items_per_page: "" },
                  showSizeChanger: true,
                  onChange: (page, pageSize) =>
                    handleChangePage(page, pageSize),
                }}
                showPagination
                rowKey="UserID"
                onRow={record => ({
                  onClick: () => handleRowClick(record),
                  style: { cursor: "pointer" },
                })}
              />
            </Col>
          </Splitter.Panel>
        </Splitter>
      </Row>

      <MemberDetailModal
        open={openMemberDetailModal}
        onCancel={() => {
          setOpenMemberDetailModal(false)
          setSelectedMember(null)
        }}
        memberData={selectedMember}
      />

      {openModal && (
        <ModalAddMember
          open={openModal}
          listUnit={listUnit}
          selectedNode={selectedNode}
          onCancel={() => setOpenModal(false)}
          onOk={getList}
          memberType={pagination?.MemberType}
        />
      )}
      {openModalInsertSelectMember && (
        <ModalInsertSelectMember
          open={openModalInsertSelectMember}
          onCancel={() => setOpenModalInsertSelectMember(false)}
          onOk={getList}
        />
      )}
    </MemberPageStyle>
  )
}

export default MemberContacts
